const PHASE_DP_MULT = [1, 1.3, 1.6] as const;
const PHASE_NAMES = ["Foundation", "Building", "Mastery"] as const;

function build30DayMap(foundation: MapNodeDef[]): MapNodeDef[] {
  const nodes: MapNodeDef[] = [];
  for (let phase = 0; phase < 3; phase++) {
    const mult = PHASE_DP_MULT[phase];
    for (const src of foundation) {
      nodes.push({
        ...src,
        dp: Math.round(src.dp * mult),
        desc: phase > 0 ? `${PHASE_NAMES[phase]}: ${src.desc}` : src.desc,
      });
    }
  }
  return nodes;
}

