  skin_ice:     { body: "#88E0EF", blush: "rgba(150,200,255,0.3)", bolt: "#FFFFFF" },
  skin_shadow:  { body: "#2D2D2D", blush: "rgba(100,100,100,0.3)", bolt: "#9B59B6" },
  skin_gold:    { body: "#FFD700", blush: "rgba(255,215,0,0.3)", bolt: "#FFA500" },
